<script setup>
import { ref, onMounted, watch } from "vue";
import cvPdf from "../assets/Jonathan_Rosas_CV.pdf";

/* ── Reveal-on-scroll directive ──
   Uso:  v-reveal           (sin delay)
         v-reveal="100"      (100ms de delay para stagger)
         v-reveal="200"      etc.
   Aplica .reveal (oculto) y, al entrar al viewport, .is-visible.
   Respeta prefers-reduced-motion. Dispara una sola vez. */
const vReveal = {
  mounted(el, binding) {
    if (typeof window === "undefined") return;

    const reduce = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;
    if (reduce) {
      el.classList.add("reveal", "is-visible");
      return;
    }

    el.classList.add("reveal");

    const delay = Number(binding.value);
    if (Number.isFinite(delay) && delay > 0) {
      el.style.transitionDelay = `${delay}ms`;
    }

    if (!("IntersectionObserver" in window)) {
      el.classList.add("is-visible");
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            el.classList.add("is-visible");
            observer.unobserve(el);
          }
        });
      },
      { threshold: 0.12, rootMargin: "0px 0px -60px 0px" }
    );
    observer.observe(el);
  },
};

const track = ref(null);

onMounted(() => {
  if (track.value) {
    const items = track.value.children;
    const clone = Array.from(items).map((item) => item.cloneNode(true));
    clone.forEach((el) => track.value.appendChild(el));
  }
});

const activeExperience = ref(0);

/* Theme management */
const theme = ref(
  document.documentElement.getAttribute("data-theme") || "dark",
);

function toggleTheme() {
  theme.value = theme.value === "dark" ? "light" : "dark";
}

watch(theme, (newTheme) => {
  document.documentElement.setAttribute("data-theme", newTheme);
  try {
    localStorage.setItem("theme", newTheme);
  } catch (e) {
    /* localStorage unavailable */
  }
  updateMetaThemeColor(newTheme);
});

function updateMetaThemeColor(currentTheme) {
  const color = currentTheme === "light" ? "#E9F1FA" : "#101D22";
  document.querySelectorAll('meta[name="theme-color"]').forEach((meta) => {
    meta.setAttribute("content", color);
  });
}
</script>

