  gap: 8px;
  height: 26px;
  background: rgba(19, 182, 236, 0.1);
  border: 1px solid rgba(19, 182, 236, 0.2);
  border-radius: 9999px;
  flex: none;
  order: 0;
  flex-grow: 0;
  color: #13b6ec;
  justify-self: start;
  animation: fadeInUp 0.6s ease both;
}

/* Blue dot */
.dot {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
  padding: 0px;
  isolation: isolate;
  width: 8px;
  height: 8px;
  flex: none;
  order: 0;
  flex-grow: 0;
  background-color: #13b6ec;
  border-radius: 50%;
}

/* Title */
.text-main {
  width: 100%;
  max-width: 592px;
  font-weight: 800;
  font-size: 30px;
  line-height: 72px;
  color: var(--color-text);
  flex: none;
  order: 0;
  align-self: stretch;
  flex-grow: 0;
  animation: fadeInUp 0.6s ease 0.1s both;
}
.text-main h1 {
  margin: 0;
}

.text-main h1 span {
  color: var(--color-accent);
}

/* Subtitle */
.subtext-main {
  width: 100%;
  max-width: 576px;
  font-weight: 500;
  font-size: 20px;
  line-height: 28px;
  display: flex;
  align-items: center;
  color: var(--color-text-muted);
  flex: none;
  order: 0;
  align-self: stretch;
  flex-grow: 0;
  animation: fadeInUp 0.6s ease 0.2s both;
}

/* Buttons row */
.button-main {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
  padding: 0px;
  gap: 16px;
  width: 100%;
  max-width: 592px;
  animation: fadeInUp 0.6s ease 0.3s both;
}

/* View Word button */
.view-word {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  padding: 10px;
  gap: 8px;
  width: 120px;
  height: 40px;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  border: none;
  border-radius: 12px;
  font-size: 12px;
  font-weight: 700;
  text-decoration: none;
  cursor: pointer;
  transition: all 0.3s ease;
}

.view-word:hover {
  background-color: var(--color-accent-dark);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(19, 182, 236, 0.3);
}

/* Contact Me button */
.contact-me {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  padding: 10px;
  gap: 8px;
  width: 120px;
  height: 40px;
  background: var(--color-bg-elevated);
  color: var(--color-text);
  border-radius: 12px;
  font-size: 15px;
  font-weight: 700;
  text-decoration: none;
  cursor: pointer;
  transition: all 0.3s ease;
  border: 1px solid var(--color-border-medium);
}

.contact-me:hover {
  background: var(--color-bg-elevated);
  border-color: var(--color-accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 24px rgba(19, 182, 236, 0.18);
}

/* Social icons row */
.icons-info-main {
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0px;
  gap: 24px;
  animation: fadeInUp 0.6s ease 0.4s both;
}
.github {
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0px;
  gap: 8px;
}

/* GitHub icon */
.icon-github {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  width: 30px;
  height: 30px;
  background: var(--color-bg-elevated);
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
}
.github p {
  color: var(--color-text-muted);
  font-size: 15px;
}

.icon-github:hover {
  background: var(--color-surface-hover);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px var(--color-shadow-sm);
}
.icon-github:hover svg {
  transform: scale(1.1);
}

.linkedin {
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0px;
  gap: 8px;
}

/* LinkedIn icon */
.icon-linkedin {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  width: 30px;
  height: 30px;
  background: var(--color-bg-elevated);
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
}

.linkedin p {
  color: var(--color-text-muted);
  font-size: 15px;
}

.icon-linkedin:hover {
  background: var(--color-surface-hover);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px var(--color-shadow-sm);
}

.icon-linkedin:hover svg {
  transform: scale(1.1);
}

.whatsapp {
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0px;
  gap: 8px;
}

/* WhatsApp icon */
.icon-whatsapp {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  width: 30px;
  height: 30px;
  background: var(--color-bg-elevated);
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
}

.whatsapp p {
  color: var(--color-text-muted);
  font-size: 15px;
}

.icon-whatsapp:hover {
  background: var(--color-surface-hover);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px var(--color-shadow-sm);
}

.icon-whatsapp:hover svg {
  transform: scale(1.1);
}

/* Right column - profile image */
.right-main {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  animation: fadeInUp 0.6s ease 0.15s both;
}
/* Profile image */
.img-main img {
  max-width: 450px;
  width: 100%;
  height: auto;
  border-radius: 20px;
  box-shadow: 0 0 60px 20px rgba(19, 182, 236, 0.25);
}

/* Skip link (a11y) */
.skip-link {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.skip-link:focus {
  position: fixed;
  top: 8px;
  left: 8px;
  width: auto;
  height: auto;
  padding: 12px 24px;
  margin: 0;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  font-size: 14px;
  font-weight: 700;
  border-radius: 8px;
  z-index: 9999;
  clip: auto;
  overflow: visible;
  text-decoration: none;
}

.second-main {
  display: grid;
  grid-template-columns: minmax(0, 1060px) minmax(360px, 1fr);
  padding: 80px 60px;
  gap: 60px;
  box-sizing: border-box;
}

.second-left-main {
  display: flex;
  flex-direction: column;
  gap: 48px;
  justify-self: start;
  width: 100%;
  max-width: 1060px;
  min-width: 0;
  box-sizing: border-box;
}

.one_seccion {
  display: grid;
  grid-template-columns: minmax(240px, 340px) minmax(0, 1fr);
  gap: 32px;
  align-items: start;
  width: 100%;
  max-width: 100%;
  min-width: 0;
}

.seccionimages {
  position: relative;
  display: block;
  width: 100%;
  max-width: 340px;
  min-width: 0;
}

.seccionimages img {
  width: 100%;
  height: auto;
  border-radius: 16px;
  display: block;
}

.iconsecurity {
  position: absolute;
  bottom: -8px;
  right: -8px;
  width: 32px;
  height: 32px;
  background-color: var(--color-accent);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 2px solid var(--color-bg);
}

.iconsecurity svg {
  width: 16px;
  height: 16px;
}

.overlay_text {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 16px;
  width: 100%;
  max-width: 720px;
  min-width: 0;
}

.textsecond {
  min-width: 0;
}

.overlaytwo {
  box-sizing: border-box;
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 4px 12px;
  height: 26px;
  background: rgba(19, 182, 236, 0.1);
  border: 1px solid rgba(19, 182, 236, 0.2);
  border-radius: 9999px;
  color: #13b6ec;
  font-size: 12px;
  font-weight: 600;
}

.textsecond h2 {
  font-size: clamp(40px, 4vw, 48px);
  font-weight: 800;
  color: var(--color-text);
  margin: 0;
  overflow-wrap: break-word;
}

.textsecond h2 span {
  color: #13b6ec;
}

.textsecond p {
  font-size: 18px;
  color: var(--color-text-muted);
  line-height: 1.6;
  margin: 8px 0 0;
}

.subtextsecond {
  display: flex;
  flex-direction: column;
  gap: 16px;
  max-width: 720px;
}

.subtextsecond p {
  font-size: 18px;
  line-height: 1.7;
  color: var(--color-text-muted);
  margin: 0;
  hyphens: none;
  overflow-wrap: break-word;
  word-break: keep-all;
}

/* ═══════════════════════════════════
