}

.dowloand-cv a {
  box-sizing: border-box;
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  padding: 16px 32px;
  gap: 12px;
  width: 311px;
  height: 60px;
  background: var(--color-bg-elevated);
  color: var(--color-text);
  border: 1px solid var(--color-border-medium);
  border-radius: 12px;
  font: inherit;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  transition:
    background 0.3s ease,
    border-color 0.3s ease,
    box-shadow 0.3s ease,
    transform 0.3s ease;
}

.dowloand-cv a:hover,
.dowloand-cv button:hover {
  background: var(--color-bg-elevated);
  border-color: var(--color-accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 24px rgba(19, 182, 236, 0.18);
}

.dowloand-cv a svg,
.dowloand-cv button svg {
  flex-shrink: 0;
  color: inherit;
}

.dowloand-cv button p {
  margin: 0;
  color: var(--color-text);
  line-height: 1;
}

.second-right-main {
  align-self: start;
  justify-self: start;
  box-sizing: border-box;
  width: 100%;
  max-width: 460px;
  min-width: 280px;
  padding: 44px 40px;
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  border-radius: 18px;
  box-shadow: 0 24px 60px var(--color-shadow-md);
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.contact-heading h2 {
  margin: 0;
  color: var(--color-text);
  font-size: 25px;
  line-height: 1.15;
  font-weight: 800;
}

.contact-heading p {
  margin: 14px 0 0;
  color: var(--color-text-muted);
  font-size: 17px;
  line-height: 1.45;
}

.form-field {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-field label {
  color: var(--color-text-muted);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 1.8px;
}

.form-field input,
.form-field textarea {
  width: 100%;
  background: var(--color-bg-elevated);
  color: var(--color-text);
  border: 1px solid rgba(148, 163, 184, 0.42);
  border-radius: 12px;
  font: inherit;
  font-size: 16px;
  outline: none;
  transition:
    border-color 0.3s ease,
    box-shadow 0.3s ease;
}

.form-field input {
  height: 58px;
  padding: 0 20px;
}

.form-field textarea {
  height: 130px;
  padding: 20px;
  line-height: 1.4;
  resize: none;
}

.form-field input::placeholder,
.form-field textarea::placeholder {
  color: rgba(148, 163, 184, 0.48);
}

.form-field input:focus,
.form-field textarea:focus {
  border-color: #13b6ec;
  box-shadow: 0 0 0 3px rgba(19, 182, 236, 0.14);
}

.send-message {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  width: 100%;
  height: 64px;
  padding: 0 24px;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  border: none;
  border-radius: 12px;
  font: inherit;
  font-size: 16px;
  font-weight: 800;
  cursor: pointer;
  transition:
    background 0.3s ease,
    box-shadow 0.3s ease,
    transform 0.3s ease;
}

.send-message:hover {
  background: var(--color-accent-hover);
  transform: translateY(-2px);
  box-shadow: 0 12px 28px rgba(19, 182, 236, 0.26);
}

.contact-divider {
  width: 100%;
  height: 1px;
  margin: 40px 0;
  background: var(--color-border);
}

.direct-contact {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 14px;
}

.direct-contact > p {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2.2px;
}

.direct-email {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  color: var(--color-text);
  font-size: 15px;
  font-weight: 800;
  line-height: 1;
}

.email-icon-space {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  flex: 0 0 24px;
}

.email-icon-space svg {
  display: block;
  width: 22px;
  height: 22px;
  flex-shrink: 0;
  color: var(--color-accent);
}

.third-section {
  position: relative;
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  padding: 80px 60px;
  box-sizing: border-box;
  background:
    radial-gradient(
      141.42% 141.42% at 0% 0%,
      rgba(19, 182, 236, 0.15) 0%,
      rgba(19, 182, 236, 0) 50%
    ),
    radial-gradient(
      141.42% 141.42% at 100% 100%,
      rgba(19, 182, 236, 0.1) 0%,
      rgba(19, 182, 236, 0) 50%
    );
}

.overlay-projects {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 24px;
  color: #13b6ec;
}

.dot-projects {
  width: 10px;
  height: 10px;
  background: #13b6ec;
  border-radius: 50%;
  box-shadow: 0 0 18px rgba(19, 182, 236, 0.65);
}

.overlay-projects p {
  margin: 0;
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 2px;
  color: var(--color-accent-lighter);
}

.featured-projects {
  width: 100%;
  max-width: 900px;
  margin-bottom: 40px;
}

.featured-projects h2 {
  margin: 0;
  color: var(--color-text);
  font-size: 60px;
  line-height: 0.95;
  font-weight: 800;
  letter-spacing: -3px;
}

.featured-projects h2 span {
  color: var(--color-accent-lighter);
}

.featured-projects p {
  max-width: 860px;
  margin: 28px 0 0;
  color: var(--color-text-muted);
  font-size: 22px;
  line-height: 1.45;
  font-weight: 500;
}

/* ═══════════════════════════════════
   PROJECTS GRID
   ═══════════════════════════════════ */
.projects-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 32px;
  width: 100%;
  max-width: 1280px;
  align-self: center;
}

.project-card {
  display: flex;
  flex-direction: column;
  background: var(--color-card-bg);
  border: none;
  border-radius: 18px;
  overflow: hidden;
}

/* Slider area */
.project-media {
  position: relative;
  width: 100%;
  aspect-ratio: 16 / 11;
  overflow: hidden;
}

.project-category {
  position: absolute;
  top: 14px;
  left: 14px;
  z-index: 5;
  padding: 5px 14px;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 1.6px;
  border-radius: 9999px;
  text-transform: uppercase;
}

.project-image-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: rgba(255, 255, 255, 0.35);
  font-size: 14px;
  font-weight: 600;
  letter-spacing: 1px;
}

.project-image-placeholder span {
  text-align: center;
  padding: 20px;
}

/* Content area */
.project-content {
  display: flex;
  flex-direction: column;
  gap: 14px;
  padding: 22px 24px 24px;
  flex: 1;
}

.project-content h3 {
  margin: 0;
  color: var(--color-text);
  font-size: 22px;
  font-weight: 800;
  line-height: 1.2;
}

.project-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.project-tags span {
  padding: 4px 12px;
  background: rgba(148, 163, 184, 0.1);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 9999px;
  color: var(--color-text-muted);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.3px;
}

.project-content p {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 14px;
  line-height: 1.6;
  flex: 1;
}

.project-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 6px;
}

.project-footer a {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: #13b6ec;
  font-size: 14px;
  font-weight: 700;
  text-decoration: none;
  transition: color 0.25s ease;
}

.project-footer a:hover {
  color: var(--color-accent-lighter);
}

.project-footer a svg {
  flex-shrink: 0;
  color: inherit;
  transition: transform 0.25s ease;
}

.project-footer a:hover svg {
  transform: translateX(4px);
}

.project-footer .project-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  background: rgba(148, 163, 184, 0.08);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 10px;
  transition:
    background 0.25s ease,
    border-color 0.25s ease;
}

.fourth-section {
  position: relative;
  width: 100%;
  min-height: 100vh;
