  margin: 28px 0 0;
  color: var(--color-text-muted);
  font-size: 22px;
  line-height: 1.45;
  font-weight: 500;
}

.experience-timeline {
  position: relative;
  display: grid;
  gap: 32px;
  width: 100%;
  max-width: 1100px;
  align-self: center;
  margin-top: 24px;
}

.experience-timeline::before {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  left: 50%;
  width: 2px;
  transform: translateX(-50%);
  background: linear-gradient(
    180deg,
    rgba(19, 182, 236, 0),
    rgba(19, 182, 236, 0.9),
    rgba(19, 182, 236, 0)
  );
}

.experience-card {
  position: relative;
  display: grid;
  grid-template-columns: 1fr 40px 1fr;
  align-items: center;
}

.experience-card:nth-child(odd) .experience-content {
  grid-column: 1;
  grid-row: 1;
  margin-right: 24px;
}

.experience-card:nth-child(odd) .experience-labels {
  grid-column: 3;
  grid-row: 1;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 6px;
  padding-left: 24px;
}

.experience-card:nth-child(even) .experience-labels {
  grid-column: 1;
  grid-row: 1;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 6px;
  padding-right: 24px;
}

.experience-card:nth-child(even) .experience-content {
  grid-column: 3;
  grid-row: 1;
  margin-left: 24px;
}

.experience-content {
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  border-radius: 18px;
  box-shadow: 0 24px 60px var(--color-shadow-md);
  padding: 26px;
  box-sizing: border-box;
  width: 100%;
}

.company-heading {
  display: flex;
  align-items: center;
  gap: 14px;
  margin-bottom: 16px;
}

.company-logo-slot {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex: 0 0 48px;
  width: 48px;
  height: 48px;
}

.company-heading h4 {
  margin: 0;
  color: var(--color-text);
  font-size: 24px;
  line-height: 1.2;
  font-weight: 800;
}

.experience-techs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 20px;
}

.experience-techs span {
  display: inline-flex;
  align-items: center;
  min-height: 30px;
  padding: 6px 14px;
  border: 1px solid rgba(19, 182, 236, 0.22);
  border-radius: 999px;
  color: #13b6ec;
  background: rgba(19, 182, 236, 0.08);
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0.8px;
  text-transform: uppercase;
}

.experience-date {
  display: inline-flex;
  color: #13b6ec;
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 1.6px;
  white-space: nowrap;
}

.experience-labels h3 {
  margin: 0;
  color: var(--color-text);
  font-size: 22px;
  line-height: 1.2;
  font-weight: 800;
}

.experience-content p {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 16px;
  line-height: 1.6;
}

.timeline-point {
  grid-column: 2;
  grid-row: 1;
  align-self: center;
  justify-self: center;
  width: 16px;
  height: 16px;
  background: var(--color-bg-elevated);
  border: 2px solid rgba(148, 163, 184, 0.45);
  border-radius: 50%;
  z-index: 2;
  transition:
    background 0.25s ease,
    border-color 0.25s ease,
    box-shadow 0.25s ease;
}

.experience-card.active .timeline-point {
  background: #13b6ec;
  border-color: #13b6ec;
  box-shadow:
    0 0 0 8px rgba(19, 182, 236, 0.12),
    0 0 24px rgba(19, 182, 236, 0.75);
}

.cta-card {
  width: 100%;
  margin-top: 60px;
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  border-radius: 24px;
  padding: 48px 40px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 16px;
}

.cta-card h2 {
  margin: 0;
  color: var(--color-text);
  font-size: 24px;
  line-height: 1.2;
  font-weight: 800;
  letter-spacing: -0.5px;
  max-width: 520px;
}

.cta-card p {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 15px;
  line-height: 1.5;
  max-width: 560px;
}

.cta-buttons {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 16px;
  margin-top: 8px;
}

.cta-primary {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 160px;
  height: 44px;
  padding: 0 24px;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  border: none;
  border-radius: 12px;
  font: inherit;
  font-size: 14px;
  font-weight: 800;
  text-decoration: none;
  cursor: pointer;
  transition:
    background 0.3s ease,
    transform 0.3s ease,
    box-shadow 0.3s ease;
}

.cta-primary:hover {
  background: var(--color-accent-hover);
  transform: translateY(-2px);
  box-shadow: 0 12px 28px rgba(19, 182, 236, 0.26);
}

.cta-secondary {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 160px;
  height: 44px;
  padding: 0 24px;
  background: transparent;
  color: var(--color-text);
  border: 1px solid var(--color-border-medium);
  border-radius: 12px;
  font: inherit;
  font-size: 14px;
  font-weight: 800;
  text-decoration: none;
  cursor: pointer;
  transition:
    background 0.3s ease,
    border-color 0.3s ease,
    transform 0.3s ease;
}

.cta-secondary:hover {
  background: var(--color-bg-elevated);
  border-color: var(--color-accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 24px rgba(19, 182, 236, 0.18);
}

.cta-card h2 {
  margin: 0;
  color: var(--color-text);
  font-size: 25px;
  line-height: 1.2;
  font-weight: 800;
  letter-spacing: -0.5px;
  max-width: 600px;
}

.cta-card p {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 17px;
  line-height: 1.5;
  max-width: 560px;
}

.cta-buttons {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 16px;
  margin-top: 16px;
}

.cta-primary {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 160px;
  height: 52px;
  padding: 0 24px;
  background: #13b6ec;
  color: var(--color-text-on-accent);
  border: none;
  border-radius: 12px;
  font: inherit;
  font-size: 15px;
  font-weight: 800;
  cursor: pointer;
  transition:
    background 0.3s ease,
    transform 0.3s ease,
    box-shadow 0.3s ease;
}

.cta-primary:hover {
  background: var(--color-accent-hover);
  transform: translateY(-2px);
  box-shadow: 0 12px 28px rgba(19, 182, 236, 0.26);
}

.cta-secondary {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 160px;
  height: 52px;
  padding: 0 24px;
  background: transparent;
  color: var(--color-text);
  border: 1px solid var(--color-border-medium);
  border-radius: 12px;
  font: inherit;
  font-size: 15px;
  font-weight: 800;
  cursor: pointer;
  transition:
    background 0.3s ease,
    border-color 0.3s ease,
    transform 0.3s ease;
}

.cta-secondary:hover {
  background: var(--color-bg-elevated);
  border-color: var(--color-accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 24px rgba(19, 182, 236, 0.18);
}

.seccion-contact {
  position: relative;
  width: 100%;
  min-height: 100vh;
  padding: 100px 40px 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  background:
    radial-gradient(
      141.42% 141.42% at 0% 0%,
      rgba(19, 182, 236, 0.18) 0%,
      rgba(19, 182, 236, 0) 50%
    ),
    radial-gradient(
      141.42% 141.42% at 100% 100%,
      rgba(19, 182, 236, 0.1) 0%,
      rgba(19, 182, 236, 0) 50%
    );
  overflow: hidden;
  box-sizing: border-box;
}

/* Decorative ambient orbs for depth */
.seccion-contact::before,
.seccion-contact::after {
  content: "";
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  z-index: 0;
  filter: blur(80px);
}

.seccion-contact::before {
  top: 20%;
  left: -10%;
  width: 500px;
  height: 500px;
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  opacity: 0.6;
}

.seccion-contact::after {
  bottom: 10%;
  right: -5%;
  width: 400px;
  height: 400px;
  background: var(--color-accent-soft);
  opacity: 0.4;
}

.contact-container {
  width: 100%;
  max-width: 1280px;
  position: relative;
  z-index: 1;
}

/* ── Header ── */
.contact-header {
  max-width: 760px;
  margin: 0 0 56px;
}

.contact-header h2 {
  font-size: 64px;
  font-weight: 800;
  line-height: 1.02;
  letter-spacing: -2.5px;
  margin: 0 0 20px;
  color: var(--color-text);
}

.contact-highlight {
  color: var(--color-accent);
  display: inline;
}

.contact-header p {
  font-size: 18px;
  line-height: 1.6;
  color: var(--color-text-muted);
  margin: 0;
  max-width: 620px;
}

/* ── Grid layout ── */
.contact-grid {
  display: grid;
  grid-template-columns: 1.4fr 1fr;
  gap: 24px;
  align-items: stretch;
}

/* ── Form card ── */
.contact-form-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  border-radius: 20px;
  padding: 48px;
  display: flex;
  flex-direction: column;
  gap: 24px;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  transition: border-color 0.3s ease;
}

.contact-form-card:focus-within {
  border-color: var(--color-accent-border);
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.form-field {
  display: flex;
  flex-direction: column;
  gap: 10px;
  min-width: 0;
}

.form-field label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1.6px;
  color: var(--color-text-muted);
  text-transform: uppercase;
}

.form-field input,
.form-field textarea {
  width: 100%;
  padding: 16px 18px;
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border-medium);
  border-radius: 12px;
  color: var(--color-text);
  font-family: inherit;
  font-size: 15px;
  font-weight: 500;
  outline: none;
  transition:
    border-color 0.3s ease,
    box-shadow 0.3s ease,
    background-color 0.3s ease;
  box-sizing: border-box;
}

.form-field input::placeholder,
.form-field textarea::placeholder {
  color: var(--color-text-muted);
  opacity: 0.65;
  font-weight: 400;
}

.form-field input:hover,
.form-field textarea:hover {
  border-color: var(--color-text-muted);
}

.form-field input:focus,
.form-field textarea:focus {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 3px var(--color-accent-soft);
  background: var(--color-bg-elevated);
}

.form-field textarea {
  resize: vertical;
  min-height: 160px;
  line-height: 1.5;
}

.contact-submit {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  align-self: flex-start;
  margin-top: 8px;
  padding: 0 32px;
  height: 56px;
  width: auto;
  background: var(--color-accent);
  color: var(--color-text-on-accent);
  border: none;
  border-radius: 12px;
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.2px;
  cursor: pointer;
  transition:
    background-color 0.3s ease,
    transform 0.3s ease,
    box-shadow 0.3s ease;
}

.contact-submit:hover {
  background: var(--color-accent-hover);
  transform: translateY(-2px);
  box-shadow: 0 12px 28px rgba(19, 182, 236, 0.28);
}

.contact-submit:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 3px;
}

.contact-submit svg {
  transition: transform 0.3s ease;
}

.contact-submit:hover svg {
  transform: translateX(4px);
}

/* ── Info column ── */
.contact-info {
  display: flex;
  flex-direction: column;
  gap: 20px;
  min-width: 0;
}

.info-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-border);
  border-radius: 20px;
  padding: 28px;
  transition:
    border-color 0.3s ease,
    transform 0.3s ease,
    background-color 0.3s ease;
  position: relative;
  overflow: hidden;
}

.info-card:hover {
  border-color: var(--color-accent-border);
}

.info-card h3 {
  margin: 0 0 18px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1.8px;
  color: var(--color-accent);
  text-transform: uppercase;
}

/* ── Direct email card ── */
.info-direct-link {
  display: flex;
  align-items: center;
  gap: 16px;
  text-decoration: none;
  color: var(--color-text);
  padding: 10px 12px;
  margin: -10px -12px;
  border-radius: 14px;
  transition: background-color 0.3s ease;
  min-width: 0;
}

.info-direct-link:hover {
  background: var(--color-accent-soft);
}

.info-icon-box {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  flex-shrink: 0;
  background: var(--color-accent-soft);
  border: 1px solid var(--color-accent-border);
  border-radius: 12px;
  color: var(--color-accent);
  transition:
    background-color 0.3s ease,
    color 0.3s ease;
}

.info-direct-link:hover .info-icon-box {
  background: var(--color-accent);
  color: var(--color-text-on-accent);
}

.info-text {
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 0;
  flex: 1;
}

.info-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  color: var(--color-text-muted);
  text-transform: uppercase;
}

.info-value {
  font-size: 16px;
  font-weight: 700;
  color: var(--color-text);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Social card ── */
.info-social-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.info-social-list li {
  margin: 0;
}

.info-social-list a {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 10px 12px;
  margin: 0 -12px;
  text-decoration: none;
  color: var(--color-text);
  border-radius: 12px;
  transition: background-color 0.3s ease;
  min-width: 0;
}

.info-social-list a:hover {
  background: var(--color-accent-soft);
}

.info-social-list a:hover .info-icon-box {
  background: var(--color-accent);
  color: var(--color-text-on-accent);
}

.info-social-list .info-icon-box {
  width: 40px;
  height: 40px;
}

.info-social-name {
  font-size: 15px;
  font-weight: 700;
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.info-arrow {
  color: var(--color-text-muted);
  flex-shrink: 0;
  transition:
    color 0.3s ease,
    transform 0.3s ease;
}

.info-social-list a:hover .info-arrow,
.info-direct-link:hover .info-arrow {
  color: var(--color-accent);
  transform: translate(2px, -2px);
}

/* ── Global reach card ── */
.info-reach {
  padding: 0;
  min-height: 180px;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
}

.info-reach-pattern {
  position: relative;
  width: 100%;
  height: 90px;
  pointer-events: none;
  overflow: hidden;
  color: var(--color-accent);
}

.info-reach-pattern::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to bottom,
    transparent 0%,
    var(--color-card-bg) 100%
  );
  pointer-events: none;
}

.info-reach-pattern svg {
  width: 100%;
  height: 100%;
  display: block;
}

.info-reach-content {
  padding: 0 28px 26px;
  position: relative;
  z-index: 1;
}

.info-reach-content h3 {
  margin: 0 0 6px;
}

.info-reach-content p {
  margin: 0;
  color: var(--color-text);
  font-size: 15px;
  font-weight: 700;
  letter-spacing: -0.1px;
}

@keyframes scrollTech {
  0% {
    transform: translateX(0);
  }
  100% {
    transform: translateX(-50%);
  }
}

/* Focus visible (a11y) */
:focus-visible {
  outline: 2px solid #13b6ec;
  outline-offset: 2px;
}

/* Stagger entrance animation */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ── Reveal-on-scroll (v-reveal directive) ──
   Inicia oculto; al entrar al viewport se le agrega
   .is-visible y la transición lo muestra. */
.reveal {
  opacity: 0;
  transform: translateY(28px);
  transition:
    opacity 0.7s cubic-bezier(0.22, 1, 0.36, 1),
    transform 0.7s cubic-bezier(0.22, 1, 0.36, 1);
  will-change: opacity, transform;
}

.reveal.is-visible {
  opacity: 1;
  transform: translateY(0);
}

@media (prefers-reduced-motion: reduce) {
  .reveal,
  .reveal.is-visible {
    opacity: 1;
    transform: none;
    transition: none;
  }
}

/* ═══════════════════════════════════════════════════════════
   FOOTER
   ═══════════════════════════════════════════════════════════ */
.layout-footer {
  width: 100%;
  padding: 16px 40px;
  background: var(--color-header-bg);
  backdrop-filter: saturate(180%) blur(12px);
  -webkit-backdrop-filter: saturate(180%) blur(12px);
  border-top: 1px solid var(--color-border);
  box-sizing: border-box;
  transition:
    background-color 0.3s ease,
    border-color 0.3s ease;
}

.footer-container {
  max-width: 1280px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  flex-wrap: wrap;
}

.footer-social {
  display: flex;
  gap: 10px;
}

.footer-social a {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border: 1px solid var(--color-border-medium);
  border-radius: 10px;
  color: var(--color-text-muted);
  transition:
    color 0.3s ease,
    border-color 0.3s ease,
    transform 0.3s ease,
    box-shadow 0.3s ease;
}

.footer-social a:hover {
  color: var(--color-accent);
  border-color: var(--color-accent);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(19, 182, 236, 0.15);
}

.footer-tagline {
  font-size: 13px;
  color: var(--color-text-muted);
  margin: 0;
  font-weight: 500;
  flex-shrink: 0;
}

.footer-heart {
  color: var(--color-accent);
}

.footer-bottom {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}

.footer-copyright {
  font-size: 13px;
  color: var(--color-text-muted);
  margin: 0;
  font-weight: 500;
}

.footer-back-top {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  color: var(--color-text-muted);
  border: 1px solid var(--color-border-medium);
  border-radius: 8px;
  text-decoration: none;
  transition:
    color 0.3s ease,
    border-color 0.3s ease,
    transform 0.3s ease,
    box-shadow 0.3s ease;
}

.footer-back-top:hover {
  color: var(--color-accent);
  border-color: var(--color-accent);
  transform: translateY(-3px);
  box-shadow: 0 6px 16px rgba(19, 182, 236, 0.15);
}

/* ═══════════════════════════════════════════════════════════
   RESPONSIVE — TABLET (≤1024px)
   Tablets en landscape y dispositivos medianos
   ═══════════════════════════════════════════════════════════ */
@media (max-width: 1024px) {
  /* ── Hero ── */
  .principal-main {
    flex-direction: column;
    align-items: center;
    padding: 0 24px;
    min-height: auto;
  }

  .left-main {
    padding: 60px 0 0;
    max-width: 100%;
    align-items: center;
    text-align: center;
  }

  .overlay {
    justify-self: center;
  }

  .text-main {
    max-width: 100%;
    text-align: center;
  }

  .subtext-main {
    max-width: 100%;
    text-align: center;
